import { createContext, useContext } from 'react';
import { Dimensions } from 'react-native';

// --- Responsive ColSpan ---

export type ResponsiveColSpan = {
  default?: number;
  base?: number;
  sm?: number;
  md?: number;
  lg?: number;
  xl?: number;
};

// --- Context Value ---

export interface GridContextValue {
  registerItem: (id: string, colSpan: number) => void;
  unregisterItem: (id: string) => void;
  getItemWidth: (id: string) => number | undefined;
  containerWidth: number;
  numColumns: number;
  columnGap: number;
  rowGap: number;
}

// --- Context ---

const GridContext = createContext<GridContextValue>({
  registerItem: () => {},
  unregisterItem: () => {},
  getItemWidth: () => undefined,
  containerWidth: 0,
  numColumns: 12,
  columnGap: 0,
  rowGap: 0,
});

export const useGridContext = () => useContext(GridContext);
export default GridContext;

// --- Breakpoints ---

const BREAKPOINTS = {
  xl: 1280,
  lg: 992,
  md: 768,
  sm: 480,
  base: 0,
} as const;

/**
 * Resolve a responsive colSpan value to a concrete number
 * based on the current screen width.
 */
export function resolveColSpan(
  value: number | ResponsiveColSpan | undefined,
  screenWidth?: number,
): number {
  if (value == null) return 12;
  if (typeof value === 'number') return value;

  const width = screenWidth ?? Dimensions.get('window').width;

  for (const [key, minWidth] of Object.entries(BREAKPOINTS)) {
    if (width >= minWidth && value[key as keyof ResponsiveColSpan] != null) {
      return value[key as keyof ResponsiveColSpan]!;
    }
  }

  return value.default ?? 12;
}

// --- Row Arrangement Algorithm ---

/**
 * Greedy row arrangement: pack items left-to-right, wrap when full.
 * Returns map of rowNumber -> array of item indices.
 */
export function arrangeIntoRows(
  colSpans: number[],
  numColumns: number,
): Record<number, number[]> {
  let currentRow = 1;
  let currentRowTotal = 0;
  const rows: Record<number, number[]> = {};

  for (let i = 0; i < colSpans.length; i++) {
    const colSpan = colSpans[i];
    if (currentRowTotal + colSpan > numColumns) {
      currentRow++;
      currentRowTotal = colSpan;
    } else {
      currentRowTotal += colSpan;
    }
    if (!rows[currentRow]) {
      rows[currentRow] = [];
    }
    rows[currentRow].push(i);
  }

  return rows;
}